import React from "react";
import { Routes, Route, Navigate } from "react-router-dom";

// Pages
import Home from "../pages/Home";
import Login from "../pages/Auth/Login";
import Register from "../pages/Auth/Register";

// Vehicles
import VehicleList from "../pages/Vehicles/VehicleList";
import AddVehicle from "../pages/Vehicles/AddVehicle";
import EditVehicle from "../pages/Vehicles/EditVehicle";

// Leads
import LeadList from "../pages/Leads/LeadList";
import AddLead from "../pages/Leads/AddLead";
import EditLead from "../pages/Leads/EditLead";

// Appointments (Staff/Admin)
import AppointmentList from "../pages/Appointments/AppointmentList";
import AddAppointment from "../pages/Appointments/AddAppointment";
import EditAppointment from "../pages/Appointments/EditAppointment";
import CreateStaff from "../pages/Admin/CreateStaff";

// Appointments (Customer)
import CustomerBookAppointment from "../pages/Appointments/CustomerBookAppointment";
import MyAppointments from "../pages/Appointments/MyAppointments";
import EditMyAppointment from "../pages/Appointments/EditMyAppointment";

// Sales
import SaleList from "../pages/Sales/SaleList";
import AddSale from "../pages/Sales/AddSale";
import EditSale from "../pages/Sales/EditSales";

//Document
import Documnt from "../"

function AppRoutes() {
  return (
    <Routes>
      {/* Home & Auth */}
      <Route path="/" element={<Home />} />
      <Route path="/vehicles" element={<VehicleList />} />
      <Route path="/login" element={<Login />} />
      <Route path="/register" element={<Register />} />

      {/* Vehicles (admin/manager will see buttons in UI) */}
      <Route path="/vehicles/add" element={<AddVehicle />} />
      <Route path="/vehicles/edit/:id" element={<EditVehicle />} />

      {/* Leads */}
      <Route path="/leads" element={<LeadList />} />
      <Route path="/leads/add" element={<AddLead />} />
      <Route path="/leads/edit/:id" element={<EditLead />} />

      {/* Staff/Admin Appointments */}
      <Route path="/appointments" element={<AppointmentList />} />
      <Route path="/appointments/add" element={<AddAppointment />} />
      <Route path="/appointments/edit/:id" element={<EditAppointment />} />
      <Route path="/admin/create-staff" element={<CreateStaff />} />

      {/* Customer Appointments */}
      <Route path="/book-appointment" element={<CustomerBookAppointment />} />
      <Route path="/my-appointments" element={<MyAppointments />} />
      <Route path="/edit-my-appointment/:id" element={<EditMyAppointment />} />

      {/* Sales */}
      <Route path="/sales" element={<SaleList />} />
      <Route path="/sales/add" element={<AddSale />} />

      {/* Payment/Transaction Update (admin/manager only on backend) */}
      <Route path="/sales/edit/:id" element={<EditSale />} />

      {/* Document */}
      <Route path="/document" element={<Document />} />

      {/* Fallback */}
      <Route path="*" element={<Navigate to="/" />} />
    </Routes>
  );
}

export default AppRoutes;
